INSERT OR IGNORE INTO `item_types` (`id`, `name`, `description`, `color`, `icon`, `guidance`, `is_system`, `sort_order`, `created_at`, `updated_at`) VALUES ('c8c19c9f-d79c-4c61-86c1-a85b61025ecd', 'Concept', 'Explanation of a core idea or principle', '#8B5CF6', '💡', '{"pattern":"[Topic]: [Core idea or principle explained]","example":"Event Sourcing: Storing state changes as an immutable sequence of events","whenToUse":"Use for explaining foundational ideas, patterns, or mental models","contentHints":"Open with a concise definition, then expand with context, related concepts, and examples. Use headings to separate Definition, How It Works, and When To Use sections."}', 1, 0, '2026-03-27T01:23:03.025Z', '2026-03-27T01:23:03.025Z');
