INSERT OR IGNORE INTO `item_types` (`id`, `name`, `description`, `color`, `icon`, `guidance`, `is_system`, `sort_order`, `created_at`, `updated_at`) VALUES ('44712533-8236-4037-86ac-d45d8176075b', 'How-To Guide', 'Step-by-step instructions for a specific task', '#3B82F6', '📝', '{"pattern":"How to [accomplish specific task] + [context or scope]","example":"How to configure CORS headers in Cloudflare Workers","whenToUse":"Use for task-oriented instructions that walk through a specific workflow","contentHints":"Start with prerequisites, then use numbered steps. Include code blocks for commands and expected output. End with verification steps and troubleshooting tips."}', 1, 1, '2026-03-27T01:23:03.025Z', '2026-03-27T01:23:03.025Z');
