INSERT OR IGNORE INTO `item_types` (`id`, `name`, `description`, `color`, `icon`, `guidance`, `is_system`, `sort_order`, `created_at`, `updated_at`) VALUES ('b23035c2-8bee-43de-84be-1415eb0f933a', 'Reference', 'Technical specification or API documentation', '#10B981', '📖', '{"pattern":"[Component/API name] — [scope of reference]","example":"Drizzle ORM — Column type reference for SQLite","whenToUse":"Use for lookup-oriented content: API surfaces, config options, type definitions","contentHints":"Use tables for parameters, options, and return types. Group related items under headings. Include code examples for each entry. Keep descriptions terse — this is a reference, not a tutorial."}', 1, 2, '2026-03-27T01:23:03.025Z', '2026-03-27T01:23:03.025Z');
