INSERT OR IGNORE INTO `item_types` (`id`, `name`, `description`, `color`, `icon`, `guidance`, `is_system`, `sort_order`, `created_at`, `updated_at`) VALUES ('28cbacf3-1f84-4271-8f9b-7f04699e78e3', 'FAQ', 'Frequently asked questions with answers', '#F59E0B', '❓', '{"pattern":"[Topic area] — Frequently Asked Questions","example":"Authentication — Frequently Asked Questions","whenToUse":"Use for collections of common questions and their answers within a topic","contentHints":"Use headings for each question (## Question). Keep answers direct — lead with the answer, then provide context. Link to related articles for deeper explanations."}', 1, 3, '2026-03-27T01:23:03.025Z', '2026-03-27T01:23:03.025Z');
