INSERT OR IGNORE INTO `item_types` (`id`, `name`, `description`, `color`, `icon`, `guidance`, `is_system`, `sort_order`, `created_at`, `updated_at`) VALUES ('2648d350-6ec3-45b0-8114-734c7c17ae65', 'Glossary Entry', 'Definition of a specific term', '#EC4899', '🔤', '{"pattern":"[Term]: [Brief definition]","example":"Idempotency: An operation that produces the same result when applied multiple times","whenToUse":"Use for defining domain-specific terms, acronyms, or jargon","contentHints":"Lead with a one-sentence definition. Follow with usage context, related terms, and examples showing the term in practice. Keep it concise — link to concept articles for depth."}', 1, 4, '2026-03-27T01:23:03.025Z', '2026-03-27T01:23:03.025Z');
