-- wiki-specific settings
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('source_title', 'My Knowledge Base', datetime('now'));
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('source_description', 'Structured documentation and reference articles', datetime('now'));
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('quality_guidelines', '{"keySummary":{"tips":"Write a descriptive title that helps readers find this article. Follow the topic-specific pattern from guidance. Example: \"How to set up CI/CD with GitHub Actions\""},"content":{"tips":"Write for someone encountering this topic for the first time. Use headings to create scannable structure. Link to related articles where relevant."},"formatting":["Headings: create a navigable hierarchy (H2 for sections, H3 for subsections)","Code blocks: commands, config snippets, API examples with language tags","Tables: parameters, options, comparisons, specifications","Numbered lists: sequential steps or procedures","Bullet lists: related items, feature lists, prerequisites","Callouts: important warnings, tips, or notes (use blockquotes)"],"avoid":["Ambiguous titles that do not indicate content scope","Missing prerequisites or assumed context","Undated references to \"current\" versions","Duplicate content — link to existing articles instead"]}', datetime('now'));
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('validation_limits', '{"keySummary":{"min":10,"max":200},"content":{"min":100,"max":30000},"sourceAi":{"min":1,"max":100}}', datetime('now'));

-- Site actions (wiki)
INSERT OR IGNORE INTO `site_actions` (`id`, `name`, `slug`, `description`, `fields`, `settings`, `status`, `created_at`, `updated_at`) VALUES ('7907e981-29b5-427e-8376-fcedd4114522', 'Suggest Edit', 'suggest-edit', 'Suggest an improvement to an article', '[{"name":"name","type":"text","label":"Name","required":true,"placeholder":"Your name","maxLength":100},{"name":"email","type":"email","label":"Email","required":true,"placeholder":"you@example.com"},{"name":"article_url","type":"url","label":"Article URL","required":false,"placeholder":"https://...","maxLength":500},{"name":"suggestion","type":"textarea","label":"Suggested Edit","required":true,"placeholder":"Describe the change you''d suggest...","maxLength":2000}]', '{"success_message":"Thanks for the suggestion! We''ll review it and update the article if appropriate.","require_honeypot":true}', 'active', '2026-03-27T01:23:03.025Z', '2026-03-27T01:23:03.025Z');
INSERT OR IGNORE INTO `site_actions` (`id`, `name`, `slug`, `description`, `fields`, `settings`, `status`, `created_at`, `updated_at`) VALUES ('a4b3b350-2b94-4580-87a3-cb9cddc32679', 'Report Issue', 'report-issue', 'Report an issue with the knowledge base', '[{"name":"name","type":"text","label":"Name","required":true,"placeholder":"Your name","maxLength":100},{"name":"email","type":"email","label":"Email","required":true,"placeholder":"you@example.com"},{"name":"issue_type","type":"select","label":"Issue Type","required":true,"options":["Outdated Information","Incorrect Content","Broken Link","Missing Topic","Other"]},{"name":"details","type":"textarea","label":"Details","required":true,"placeholder":"Describe the issue...","maxLength":2000}]', '{"success_message":"Issue reported! We''ll investigate and make corrections as needed.","require_honeypot":true}', 'active', '2026-03-27T01:23:03.025Z', '2026-03-27T01:23:03.025Z');
